from fastapi import HTTPException, status
from pydantic import EmailStr
from sqlalchemy.orm import Session

from app import models, schemas
from app.core import security
from app.crud.base import CRUDBase
from app.schemas import UserUpdate


class User(CRUDBase[models.User, schemas.UserCreate, UserUpdate]):
    def get_by_email(self, db: Session, *, email: EmailStr) -> Optional[models.User]:
        return db.query(models.User).filter(models.User.email == email).first()

    def authenticate(self, db: Session, *, email: EmailStr, password: str) -> Optional[models.User]:
        user = self.get_by_email(db, email=email)
        if not user:
            return None
        if not security.verify_password(password, user.hashed_password):
            return None
        return user

    def create(self, db: Session, *, obj_in: schemas.UserCreate) -> models.User:
        db_obj = models.User(**obj_in.dict())
        db.add(db_obj)
        db.commit()
        db.refresh(db_obj)
        return db_obj

    def get_by_id(self, db: Session, *, id: int) -> Optional[models.User]:
        return db.query(models.User).filter(models.User.id == id).first()

    def update(self, db: Session, *, id: int, obj_in: UserUpdate) -> models.User:
        db_obj = self.get_by_id(db, id=id)
